// AvisaAPI envia o payload no body da requisição
// O N8N encapsula em item.json.body (quando parse=true) ou item.json diretamente
const raw = $input.first().json;
const body = raw.body || raw;

// Campos esperados do webhook AvisaAPI (ajustar conforme payload real observado nos logs)
// Campos comuns em APIs WhatsApp: number/from, message/text, session, id
const numeroRemetente = (
  body.number ||
  body.from ||
  body.sender ||
  body.phone ||
  ''
).replace(/[^0-9]/g, '');  // garantir apenas dígitos

const mensagemCliente = (
  body.message ||
  body.text ||
  body.body ||
  body.content ||
  ''
).trim();

const sessionId = body.session || body.session_id || body.chatId || body.chat_id || null;
const messageId = body.id || body.message_id || body.msgId || null;
const nomeRemetente = body.name || body.pushName || body.from_name || 'Cliente';

if (!numeroRemetente) {
  throw new Error('Webhook recebido sem número do remetente: ' + JSON.stringify(body));
}

if (!mensagemCliente) {
  // Mensagem vazia ou mídia — ignorar silenciosamente
  return [{ json: { _skip: true, motivo: 'mensagem vazia ou tipo não suportado', body } }];
}

// Construir body para Groq
const groqBody = {
  model: 'llama-3.3-70b-versatile',
  messages: [
    {
      role: 'system',
      content: 'Você é o assistente jurídico da Fenice IT Justech.IA, atendendo via WhatsApp. ' +
        'Cliente: ' + nomeRemetente + '. ' +
        'Seja profissional, empático e objetivo. ' +
        'Conhecimento sólido em direito brasileiro (Código Civil, CLT, Código Penal, CF/88). ' +
        'Responda SEMPRE em português (BR), de forma concisa e clara para WhatsApp. ' +
        'Se não tiver certeza jurídica, diga que não temos resposta bate-pronto e que pode pesquisar. ' +
        'Nunca invente leis, artigos ou jurisprudência inexistentes. ' +
        '© 2026 Fenice IT Justech.IA — Tech Lead: Ramão Bueno da Silva Neto'
    },
    {
      role: 'user',
      content: mensagemCliente
    }
  ],
  max_tokens: 800,
  temperature: 0.7
};

return [{
  json: {
    _skip: false,
    numero_remetente: numeroRemetente,
    nome_remetente: nomeRemetente,
    email_remetente: body.email || null,
    session_id: sessionId,
    message_id: messageId,
    mensagem_cliente: mensagemCliente,
    groq_request_body: JSON.stringify(groqBody)
  }
}];

const groqResult = $input.first().json;
const dadosOriginais = $('Extrair Dados do Webhook').first().json;

// Extrair resposta do Groq com fallback
const respostaAi = (groqResult.choices && groqResult.choices.length > 0)
  ? groqResult.choices[0].message.content
  : 'Desculpe, não consegui processar sua mensagem no momento. Tente novamente em instantes.';

// Número no formato E.164 sem + para AvisaAPI
const numero = dadosOriginais.numero_remetente;

// Body para envio via AvisaAPI
const avisaBody = JSON.stringify({
  number: numero,
  message: respostaAi
});

// Body para log no Supabase
const supabaseBody = JSON.stringify({
  numero_remetente: numero,
  nome_remetente: dadosOriginais.nome_remetente,
  email_remetente: dadosOriginais.email_remetente,
  session_id: dadosOriginais.session_id,
  message_id: dadosOriginais.message_id,
  mensagem_cliente: dadosOriginais.mensagem_cliente,
  resposta_ai: respostaAi,
  modelo_ai: groqResult.model || 'llama-3.3-70b-versatile',
  provider: 'avisa',
  canal: 'whatsapp'
});

return [{
  json: {
    numero_remetente: numero,
    resposta_ai: respostaAi,
    avisa_request_body: avisaBody,
    supabase_request_body: supabaseBody
  }
}];

const avisaResult = $input.first().json;
const dadosMontar = $('Montar Resposta + Bodies').first().json;

// AvisaAPI retorna { status: true, message: 'Message sent successfully', data: {...} }
// status=true significa entregue com sucesso
const entregue = avisaResult.status === true;
const httpStatus = avisaResult.data?.response?.code || 200;
const messageId = avisaResult.data?.response?.data?.Id || null;

const supabaseBodyObj = JSON.parse(dadosMontar.supabase_request_body);
supabaseBodyObj.entregue = entregue;
supabaseBodyObj.http_status_avisa = httpStatus;
if (messageId) supabaseBodyObj.message_id = messageId;

return [{
  json: {
    ...dadosMontar,
    supabase_request_body: JSON.stringify(supabaseBodyObj),
    entregue,
    http_status_avisa: httpStatus,
    avisa_message_id: messageId
  }
}];
